const http = require("http");
const fs = require("fs");
const path = require("path");
const crypto = require("crypto");
const ROOT = __dirname;
const PUBLIC = path.join(ROOT, "public");
const PROJECTS = path.join(ROOT, "projects");
const WORKSPACE = path.join(ROOT, "workspace", "assets");
const EXPORTS = path.join(ROOT, "exports", "builds");
const GAME = path.resolve(ROOT, "..", "..", "holotapes", "BigIron");
const MAX_BODY = 64 * 1024 * 1024;
const ASSET_EXTENSIONS = new Set([".png", ".bmp", ".jpg", ".jpeg", ".img", ".bin", ".json", ".avi", ".wav"]);
const MIME = {
".html": "text/html; charset=utf-8",
".css": "text/css; charset=utf-8",
".js": "text/javascript; charset=utf-8",
".json": "application/json; charset=utf-8",
".png": "image/png",
".bmp": "image/bmp",
".jpg": "image/jpeg",
".jpeg": "image/jpeg",
".wav": "audio/wav",
".avi": "video/x-msvideo",
".img": "application/octet-stream",
".bin": "application/octet-stream",
".zip": "application/zip"
};
for (const directory of [PROJECTS, WORKSPACE, EXPORTS]) fs.mkdirSync(directory, { recursive: true });
function json(res, status, value) {
const body = Buffer.from(JSON.stringify(value));
res.writeHead(status, {
"Content-Type": "application/json; charset=utf-8",
"Content-Length": body.length,
"Cache-Control": "no-store"
});
res.end(body);
}
function fail(res, status, message) {
json(res, status, { ok: false, error: String(message || "Request failed") });
}
function safeId(value, fallback) {
const id = String(value || fallback || "project").trim().replace(/[^a-zA-Z0-9_-]+/g, "-").replace(/^-+|-+$/g, "");
return id || fallback || "project";
}
function safeRelative(value) {
const normalized = String(value || "").replace(/\\/g, "/").replace(/^\/+/, "");
if (!normalized || normalized.split("/").some((part) => !part || part === "." || part === "..")) throw new Error("Invalid relative path");
return normalized;
}
function within(base, relative) {
const target = path.resolve(base, safeRelative(relative));
const root = path.resolve(base) + path.sep;
if (target !== path.resolve(base) && !target.startsWith(root)) throw new Error("Path leaves its allowed folder");
return target;
}
function walk(base, current, output) {
const directory = path.join(base, current || "");
if (!fs.existsSync(directory)) return output;
for (const entry of fs.readdirSync(directory, { withFileTypes: true })) {
const relative = path.posix.join((current || "").replace(/\\/g, "/"), entry.name);
if (entry.isDirectory()) walk(base, relative, output);
else if (ASSET_EXTENSIONS.has(path.extname(entry.name).toLowerCase())) output.push(relative);
}
return output;
}
function assetInfo(source, base, relative) {
const file = within(base, relative);
const stat = fs.statSync(file);
const extension = path.extname(relative).toLowerCase();
const item = {
id: source + ":" + relative.replace(/\\/g, "/"),
source,
path: relative.replace(/\\/g, "/"),
name: path.basename(relative),
extension,
bytes: stat.size,
type: [".png", ".bmp", ".jpg", ".jpeg", ".img", ".bin"].includes(extension) ? "image" : extension === ".avi" ? "video" : extension === ".wav" ? "audio" : "data"
};
if (extension === ".img" && stat.size >= 4) {
const head = Buffer.alloc(4);
const fd = fs.openSync(file, "r");
fs.readSync(fd, head, 0, 4, 0);
fs.closeSync(fd);
item.width = head[0];
item.height = head[1];
item.bpp = head[2] & 0x7f;
item.transparent = !!(head[2] & 0x80);
item.format = "espruino-img";
} else if (extension === ".bin") {
if (stat.size === 888000) Object.assign(item, { width: 1440, height: 1080, bpp: 2, format: "world-pages-2bpp" });
else if (stat.size === 54720) Object.assign(item, { width: 480, height: 456, bpp: 2, format: "raw-2bpp" });
else if (stat.size === 38400) Object.assign(item, { width: 480, height: 320, bpp: 2, format: "raw-2bpp" });
else if (stat.size === 1350) Object.assign(item, { width: 120, height: 90, bpp: 1, format: "collision-1bpp" });
else if (stat.size === 867) Object.assign(item, { width: 102, height: 34, bpp: 2, format: "raw-2bpp" });
else item.format = "binary";
}
return item;
}
function catalog() {
const items = [];
for (const relative of walk(GAME, "", [])) items.push(assetInfo("game", GAME, relative));
for (const relative of walk(WORKSPACE, "", [])) items.push(assetInfo("workspace", WORKSPACE, relative));
return items.sort((a, b) => a.name.localeCompare(b.name));
}
function collisionSeed() {
const file = path.join(GAME, "Assets", "DATA", "C.BIN");
return fs.existsSync(file) && fs.statSync(file).size === 1350 ? fs.readFileSync(file).toString("base64") : Buffer.alloc(1350).toString("base64");
}
