function projectFile(id) {
return path.join(PROJECTS, safeId(id, "bigiron-current") + ".json");
}
function readProject(id) {
const file = projectFile(id);
if (!fs.existsSync(file)) return seedProject();
return JSON.parse(fs.readFileSync(file, "utf8"));
}
function saveProject(project) {
if (!project || typeof project !== "object") throw new Error("Project data is required");
project.id = safeId(project.id, "bigiron-current");
project.schemaVersion = 2;
project.updatedAt = new Date().toISOString();
const file = projectFile(project.id);
fs.writeFileSync(file, JSON.stringify(project, null, 2));
return project;
}
function readBody(req) {
return new Promise((resolve, reject) => {
const chunks = [];
let size = 0;
req.on("data", (chunk) => {
size += chunk.length;
if (size > MAX_BODY) {
reject(new Error("Request is larger than 64 MB"));
req.destroy();
return;
}
chunks.push(chunk);
});
req.on("end", () => {
try {
resolve(chunks.length ? JSON.parse(Buffer.concat(chunks).toString("utf8")) : {});
} catch (error) {
reject(new Error("Invalid JSON request"));
}
});
req.on("error", reject);
});
}
function crc32(buffer) {
let crc = 0xffffffff;
for (const byte of buffer) {
crc ^= byte;
for (let bit = 0; bit < 8; bit += 1) crc = (crc >>> 1) ^ ((crc & 1) ? 0xedb88320 : 0);
}
return (crc ^ 0xffffffff) >>> 0;
}
function dosDateTime(date) {
const year = Math.max(1980, date.getFullYear());
return {
date: ((year - 1980) << 9) | ((date.getMonth() + 1) << 5) | date.getDate(),
time: (date.getHours() << 11) | (date.getMinutes() << 5) | Math.floor(date.getSeconds() / 2)
};
}
function makeZip(files) {
const local = [];
const central = [];
let offset = 0;
const now = dosDateTime(new Date());
for (const file of files) {
const name = Buffer.from(file.path.replace(/\\/g, "/"));
const data = file.data;
const crc = crc32(data);
const head = Buffer.alloc(30);
head.writeUInt32LE(0x04034b50, 0);
head.writeUInt16LE(20, 4);
head.writeUInt16LE(0, 6);
head.writeUInt16LE(0, 8);
head.writeUInt16LE(now.time, 10);
head.writeUInt16LE(now.date, 12);
head.writeUInt32LE(crc, 14);
head.writeUInt32LE(data.length, 18);
head.writeUInt32LE(data.length, 22);
head.writeUInt16LE(name.length, 26);
head.writeUInt16LE(0, 28);
local.push(head, name, data);
const directory = Buffer.alloc(46);
directory.writeUInt32LE(0x02014b50, 0);
directory.writeUInt16LE(20, 4);
directory.writeUInt16LE(20, 6);
directory.writeUInt16LE(0, 8);
directory.writeUInt16LE(0, 10);
directory.writeUInt16LE(now.time, 12);
directory.writeUInt16LE(now.date, 14);
directory.writeUInt32LE(crc, 16);
directory.writeUInt32LE(data.length, 20);
directory.writeUInt32LE(data.length, 24);
directory.writeUInt16LE(name.length, 28);
directory.writeUInt16LE(0, 30);
directory.writeUInt16LE(0, 32);
directory.writeUInt16LE(0, 34);
directory.writeUInt16LE(0, 36);
directory.writeUInt32LE(0, 38);
directory.writeUInt32LE(offset, 42);
central.push(directory, name);
offset += head.length + name.length + data.length;
}
const centralSize = central.reduce((sum, part) => sum + part.length, 0);
const end = Buffer.alloc(22);
end.writeUInt32LE(0x06054b50, 0);
end.writeUInt16LE(0, 4);
end.writeUInt16LE(0, 6);
end.writeUInt16LE(files.length, 8);
end.writeUInt16LE(files.length, 10);
end.writeUInt32LE(centralSize, 12);
end.writeUInt32LE(offset, 16);
end.writeUInt16LE(0, 20);
return Buffer.concat([...local, ...central, end]);
}
function buildProject(payload) {
const project = saveProject(payload.project);
const id = safeId(project.id, "bigiron-current");
const directory = path.join(EXPORTS, id);
fs.mkdirSync(directory, { recursive: true });
const written = [];
let total = 0;
for (const entry of payload.files || []) {
const relative = safeRelative(entry.path);
const data = Buffer.from(String(entry.data || ""), "base64");
if (!data.length && entry.allowEmpty !== true) throw new Error("Generated file is empty: " + relative);
if (data.length > 16 * 1024 * 1024) throw new Error("Generated file is too large: " + relative);
const file = within(directory, relative);
fs.mkdirSync(path.dirname(file), { recursive: true });
fs.writeFileSync(file, data);
written.push({ path: relative, bytes: data.length, data });
total += data.length;
}
const manifest = {
project: project.name,
projectId: id,
generatedAt: new Date().toISOString(),
totalBytes: total,
files: written.map(({ path: filePath, bytes }) => ({ path: filePath, bytes }))
};
fs.writeFileSync(path.join(directory, "BUILD-MANIFEST.json"), JSON.stringify(manifest, null, 2));
const zipFiles = written.map((file) => ({ path: file.path, data: file.data }));
zipFiles.push({ path: "BUILD-MANIFEST.json", data: Buffer.from(JSON.stringify(manifest, null, 2)) });
const zipPath = path.join(EXPORTS, id + ".zip");
fs.writeFileSync(zipPath, makeZip(zipFiles));
return { ok: true, manifest, directory, zip: zipPath, download: "/api/build/download?id=" + encodeURIComponent(id) };
}
function serveFile(res, file, downloadName) {
const stat = fs.statSync(file);
const headers = {
"Content-Type": MIME[path.extname(file).toLowerCase()] || "application/octet-stream",
"Content-Length": stat.size,
"Cache-Control": "no-store"
};
if (downloadName) headers["Content-Disposition"] = "attachment; filename=\"" + downloadName.replace(/[^a-zA-Z0-9_.-]/g, "-") + "\"";
res.writeHead(200, headers);
fs.createReadStream(file).pipe(res);
}
async function api(req, res, url) {
if (req.method === "GET" && url.pathname === "/api/bootstrap") {
const project = readProject(url.searchParams.get("id") || "bigiron-current");
return json(res, 200, { ok: true, project, assets: catalog(), roots: { game: GAME, projects: PROJECTS, exports: EXPORTS } });
}
if (req.method === "GET" && url.pathname === "/api/file") {
const source = url.searchParams.get("source");
const base = source === "game" ? GAME : source === "workspace" ? WORKSPACE : null;
if (!base) return fail(res, 400, "Unknown asset source");
const file = within(base, url.searchParams.get("path"));
if (!fs.existsSync(file) || !fs.statSync(file).isFile()) return fail(res, 404, "Asset not found");
return serveFile(res, file);
}
if (req.method === "GET" && url.pathname === "/api/build/download") {
const id = safeId(url.searchParams.get("id"), "bigiron-current");
const file = path.join(EXPORTS, id + ".zip");
if (!fs.existsSync(file)) return fail(res, 404, "Build ZIP not found");
return serveFile(res, file, id + "-bird-build.zip");
}
if (req.method === "POST" && url.pathname === "/api/project") {
const body = await readBody(req);
return json(res, 200, { ok: true, project: saveProject(body.project || body) });
}
if (req.method === "POST" && url.pathname === "/api/import") {
const body = await readBody(req);
const original = path.basename(String(body.name || "asset.bin"));
const originalExtension = path.extname(original);
const extension = originalExtension.toLowerCase();
if (!ASSET_EXTENSIONS.has(extension)) return fail(res, 400, "Unsupported asset type");
const folder = safeId(body.folder, "imports");
const name = safeId(original.slice(0, original.length - originalExtension.length), "asset") + extension;
const relative = path.posix.join(folder, name);
const data = Buffer.from(String(body.data || ""), "base64");
if (!data.length) return fail(res, 400, "Uploaded asset is empty");
if (data.length > 16 * 1024 * 1024) return fail(res, 413, "Asset is larger than 16 MB");
const file = within(WORKSPACE, relative);
fs.mkdirSync(path.dirname(file), { recursive: true });
fs.writeFileSync(file, data);
return json(res, 200, { ok: true, asset: assetInfo("workspace", WORKSPACE, relative) });
}
if (req.method === "POST" && url.pathname === "/api/build") {
const body = await readBody(req);
return json(res, 200, buildProject(body));
}
return false;
}
function staticRequest(res, url) {
let relative = decodeURIComponent(url.pathname === "/" ? "/index.html" : url.pathname).replace(/^\/+/, "");
if (relative.includes("..")) return fail(res, 400, "Invalid path");
const file = path.join(PUBLIC, relative);
if (!file.startsWith(PUBLIC + path.sep) || !fs.existsSync(file) || !fs.statSync(file).isFile()) return fail(res, 404, "Not found");
serveFile(res, file);
}
function createServer() {
return http.createServer(async (req, res) => {
const url = new URL(req.url, "http://127.0.0.1");
try {
if (url.pathname.startsWith("/api/")) {
const handled = await api(req, res, url);
if (handled !== false) return;
}
if (req.method !== "GET" && req.method !== "HEAD") return fail(res, 405, "Method not allowed");
staticRequest(res, url);
} catch (error) {
fail(res, 500, error && error.message ? error.message : error);
}
});
}
function listen(port, attempts) {
const server = createServer();
server.once("error", (error) => {
if (error.code === "EADDRINUSE" && attempts < 9) return listen(port + 1, attempts + 1);
console.error("B.I.R.D. failed to start:", error.message);
process.exitCode = 1;
});
server.listen(port, "127.0.0.1", () => {
console.log("B.I.R.D. 2 is running at http://127.0.0.1:" + port + "/");
console.log("Project source:", GAME);
});
}
if (process.argv.includes("--check")) {
const project = readProject("bigiron-current");
const hash = crypto.createHash("sha1").update(JSON.stringify(project)).digest("hex").slice(0, 10);
console.log("B.I.R.D. server check OK", hash, catalog().length + " assets");
} else {
listen(Number(process.env.BIRD_PORT) || 7331, 0);
}
